Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView Command="{Binding RefreshCommand}"
                 IsRefreshing="{Binding IsRefreshing}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem}"
                        SelectionChangedCommand="{Binding SelectionChangedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <Grid Padding="10" ColumnDefinitions="*,Auto">
                        <Label Text="{Binding Name}" FontSize="16" />
                        <Label Grid.Column="1" Text="{Binding Status}"
                               TextColor="Gray" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>

    </RefreshView>
</ContentPage>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private ItemModel? _selectedItem;

    [ObservableProperty]
    private ObservableCollection<ItemModel> _items = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<ItemModel>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChanged()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // deselect so they can re-tap
    }
}
```

**Key bindings explained:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload on pull-down |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls spinner; set `false` when done |
| `CollectionView.ItemsSource` | `Items` | The data collection |
| `CollectionView.SelectedItem` | `SelectedItem` | Two-way bind to track selection |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires navigation on tap |

**Important details:**
- Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on errors.
- Set `SelectedItem = null` after navigating so the same item can be tapped again when the user returns.
- `SelectionMode="Single"` enforces one-at-a-time selection. Use `"Multiple"` with `SelectedItems` if you need multi-select.
- This uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`). Install it via `CommunityToolkit.Mvvm` NuGet package.
